7445   // spuriously fail.  In those cases, the old value may equal the expected
7446   // value but it is possible for the swap to not occur.
7447   if (I.getPredicate() == ICmpInst::ICMP_EQ)
7448     if (auto *EVI = dyn_cast<ExtractValueInst>(Op0))
7449       if (auto *ACXI = dyn_cast<AtomicCmpXchgInst>(EVI->getAggregateOperand()))
7450         if (EVI->getIndices()[0] == 0 && ACXI->getCompareOperand() == Op1 &&
7451             !ACXI->isWeak())
7452           return ExtractValueInst::Create(ACXI, 1);
7453 
7454   if (Instruction *Res = foldICmpWithHighBitMask(I, Builder))
7455     return Res;
7456 
7457   if (I.getType()->isVectorTy())
7458     if (Instruction *Res = foldVectorCmp(I, Builder))
7459       return Res;
7460 
7461   if (Instruction *Res = foldICmpInvariantGroup(I))
7462     return Res;
7463 
7464   if (Instruction *Res = foldReductionIdiom(I, Builder, DL))
7465     return Res;
7466 
7467   return Changed ? &I : nullptr;
7468 }
